import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import {
  LayoutDashboard,
  Users,
  Building2,
  CalendarDays,
  Clock,
  Wallet,
  UserPlus,
  TrendingUp,
  MessageSquare,
  ScrollText,
  PanelLeftClose,
  PanelLeft,
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

export default function Sidebar() {
  const [collapsed, setCollapsed] = useState(false);
  const { hasRole } = useAuth();

  const NAV = [
    { to: '/dashboard',   label: 'Dashboard',    icon: LayoutDashboard, roles: null },
    { to: '/employees',   label: 'Employees',    icon: Users,           roles: ['admin', 'hr'] },
    { to: '/departments', label: 'Departments',  icon: Building2,       roles: ['admin', 'hr'] },
    { to: '/leaves',      label: 'Leave',        icon: CalendarDays,    roles: null },
    { to: '/attendance',  label: 'Attendance',   icon: Clock,           roles: null },
    { to: '/payroll',     label: 'Payroll',      icon: Wallet,          roles: ['admin', 'hr', 'accountant'] },
    { to: '/onboarding',  label: 'Onboarding',   icon: UserPlus,        roles: ['admin', 'hr', 'employee'] },
    { to: '/performance', label: 'Performance',  icon: TrendingUp,      roles: null },
    { to: '/chat',        label: 'AI Assistant', icon: MessageSquare,   roles: null },
    { to: '/audit',       label: 'Audit Logs',   icon: ScrollText,      roles: ['admin'] },
  ].filter((i) => !i.roles || hasRole(...i.roles));

  const w = collapsed ? 72 : 248;

  return (
    <aside
      style={{
        width: w,
        minWidth: w,
        background: 'var(--sidebar-bg)',
        display: 'flex',
        flexDirection: 'column',
        transition: 'width 0.25s ease',
        borderRight: '1px solid rgba(255,255,255,0.06)',
        height: '100%',
        overflow: 'hidden',
      }}
    >
      {/* Logo */}
      <div
        style={{
          padding: collapsed ? '18px 16px' : '20px 20px',
          borderBottom: '1px solid var(--sidebar-border)',
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          minHeight: 'var(--topbar-h)',
        }}
      >
        <div
          style={{
            width: 36,
            height: 36,
            borderRadius: 'var(--radius-lg)',
            background: 'linear-gradient(135deg, #0052CC, #0065FF)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: '#fff',
            fontWeight: 700,
            fontSize: 16,
            flexShrink: 0,
            boxShadow: '0 2px 8px rgba(0,82,204,0.4)',
          }}
        >
          U
        </div>
        {!collapsed && (
          <span
            style={{
              fontSize: 18,
              fontWeight: 700,
              color: 'var(--sidebar-text-active)',
              letterSpacing: '-0.02em',
              whiteSpace: 'nowrap',
            }}
          >
            UniHRM
          </span>
        )}
      </div>

      {/* Navigation */}
      <nav
        style={{
          flex: 1,
          padding: collapsed ? '12px 8px' : '12px 12px',
          overflowY: 'auto',
          display: 'flex',
          flexDirection: 'column',
          gap: 2,
        }}
      >
        {NAV.map(({ to, label, icon: Icon }) => (
          <NavLink
            key={to}
            to={to}
            title={collapsed ? label : undefined}
            style={({ isActive }) => ({
              display: 'flex',
              alignItems: 'center',
              gap: 12,
              padding: collapsed ? '11px 0' : '10px 14px',
              justifyContent: collapsed ? 'center' : 'flex-start',
              borderRadius: 'var(--radius)',
              color: isActive ? 'var(--sidebar-text-active)' : 'var(--sidebar-text)',
              textDecoration: 'none',
              fontSize: 14,
              fontWeight: isActive ? 600 : 400,
              background: isActive ? 'var(--sidebar-active)' : 'transparent',
              transition: 'all 0.15s ease',
              position: 'relative',
            })}
            onMouseEnter={(e) => {
              if (!e.currentTarget.classList.contains('active')) {
                e.currentTarget.style.background = 'var(--sidebar-hover)';
              }
            }}
            onMouseLeave={(e) => {
              if (!e.currentTarget.classList.contains('active')) {
                const isActive = e.currentTarget.getAttribute('aria-current');
                if (!isActive) e.currentTarget.style.background = 'transparent';
              }
            }}
          >
            <Icon size={20} strokeWidth={1.75} style={{ flexShrink: 0 }} />
            {!collapsed && <span style={{ whiteSpace: 'nowrap' }}>{label}</span>}
          </NavLink>
        ))}
      </nav>

      {/* Collapse toggle */}
      <div style={{ padding: '12px', borderTop: '1px solid var(--sidebar-border)' }}>
        <button
          onClick={() => setCollapsed((c) => !c)}
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: collapsed ? 'center' : 'flex-start',
            gap: 10,
            width: '100%',
            background: 'var(--sidebar-hover)',
            border: 'none',
            borderRadius: 'var(--radius)',
            padding: '9px 14px',
            color: 'var(--sidebar-text)',
            cursor: 'pointer',
            fontSize: 13,
            fontWeight: 500,
            transition: 'all 0.15s',
          }}
        >
          {collapsed ? <PanelLeft size={18} /> : <PanelLeftClose size={18} />}
          {!collapsed && 'Collapse'}
        </button>
      </div>
    </aside>
  );
}
